#include <iostream>
#include <vector>
#include <string>
#include <random>
#include <algorithm>
#include <cmath>

// Define the target string for the binary search
std::string target = "10101010101010101010";

// Function to generate a random binary string of a given length
std::string generateRandomString(int length) {
    std::string str(length, '0');
    for (int i = 0; i < length; ++i) {
        str[i] = (rand() % 2) + '0';
    }
    return str;
}

// Fitness function to evaluate how close a string is to the target
int fitness(const std::string& candidate) {
    int score = 0;
    for (size_t i = 0; i < candidate.size(); ++i) {
        if (candidate[i] == target[i]) {
            score++;
        }
    }
    return score;
}

// Selection function using tournament selection
std::string tournamentSelection(const std::vector<std::string>& population, int tournamentSize) {
    std::vector<std::string> tournament;
    tournament.reserve(tournamentSize);
    for (int i = 0; i < tournamentSize; ++i) {
        tournament.push_back(population[rand() % population.size()]);
    }
    return *std::max_element(tournament.begin(), tournament.end(), [](const std::string& a, const std::string& b) {
        return fitness(a) < fitness(b);
    });
}

